class Solution:
    def countComponents(self, n: int, edges: List[List[int]]) -> int:
        visited = set()
        count = 0
        for node in range(n):
            if node not in visited:
                count += 1
                self._dfs(node, edges, visited)
        return count

    def _dfs(self, node, edges, visited):
        visited.add(node)
        for neighbor in edges[node]:
            if neighbor not in visited:
                self._dfs(neighbor, edges, visited)

solutions.cpp:
class Solution {
public:
    int countComponents(int n, vector<vector<int>>& edges) {
        vector<bool> visited(n, false);
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                count++;
                _dfs(i, edges, visited);
            }
        }
        return count;
    }

    void _dfs(int node, vector<vector<int>>& edges, vector<bool>& visited) {
        visited[node] = true;
        for (int neighbor : edges[node]) {
            if (!visited[neighbor]) {
                _dfs(neighbor, edges, visited);
            }
        }
    }
};
